var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…사장님?","JPN":"……社長？","ENG":"Boss?","TWN":"…老闆？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아시다시피, 관리국에서는 정기적으로 태스크포스 컨퍼런스를 주최합니다.","JPN":"ご存知のとおり、管理局では定期的にタスクフォースコンファレンスを主催しています。","ENG":"As you know, the Administration periodically holds a TASKFORCE conference.","TWN":"老闆，你也知道管理局會定期舉行特遣勢力會議。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 정식으로 등록된 태스크포스라면, 컨퍼런스에 참가할 수 있는 초대권이 주어지죠.","JPN":"そして正式に登録されているタスクフォースであれば、コンファレンスに参加できる招待状が送られます。","ENG":"Invitations are given to every officially registered TASKFORCE.","TWN":"而且會邀請正式登記的特遣勢力參與會議。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"태스크포스의 업계 동향이라든지, 다른 회사 대표들 간 인맥을 쌓는 등…","JPN":"タスクフォース業界の動向を探り、他社の代表と人脈を作るなど……","ENG":"You can find out what’s going on in the TASKFORCE industry, make connections with other company presidents...","TWN":"在會議中不僅可以知道特遣勢力業界的最新動態，也可以和其他公司的老闆交流，累積人脈…"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"여러모로 저희처럼 작은 회사에는 좋은 기회라고 할 수 있습니다.","JPN":"様々な点で、我々のような小さい会社にとっては絶好の機会といえます。","ENG":"This will be a good thing for us.","TWN":"對我們這種小公司來說，是非常好的機會。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무엇보다도 참여 태스크포스는 절세 혜택이 주어지죠.","JPN":"なにより、参加するタスクフォースは節税の恩恵を受けられます。","ENG":"Plus, any company that attends the conference receives a tax break.","TWN":"更重要的是，參與的特遣勢力可以拿到好處！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음……","JPN":"ふむ……","ENG":"Okay...","TWN":"嗯……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런 사소한 일은 부사장이 알아서 처리하게.","JPN":"そういう細かなことは副社長の判断で処理したまえ。","ENG":"That sounds like a miscellaneous job, you can have it.","TWN":"像這種小事，副總你處理就好。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_HIPHOP_NULL","text":{"KOREA":"난 지금 막 새로운 비트의 영감을 받았거든!","JPN":"私はたった今、新しいビートが思い浮かんだのだ！","ENG":"Because I just had an idea for a hot new beat!","TWN":"我腦袋裡突然想到一段新的節奏！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"분명, 지난번 컨퍼런스까지는 그렇게 해 왔죠.","JPN":"確かに、この前のコンファレンスまではそうしてきました。","ENG":"That’s right. I’m the one who’s been participating the conference so far.","TWN":"這種小事，之前一直是我在處理的沒錯。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"왜냐하면, 그때는 제가 대표였으니까요.","JPN":"なぜなら、その時は私が代表でしたから。","ENG":"But that’s because I was the CEO of the company.","TWN":"因為在這之前我還是公司的老闆。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_HIPHOP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"…설마.","JPN":"まさか……","ENG":"You don’t say.","TWN":"…該不會…"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 컨퍼런스는 대표 본인이 직접 참석해야 하거든요. 대리참석은 불가하고요.","JPN":"このコンファレンスは代表自らが参加する必要があります。代理の参加は認められていませんので。","ENG":"The CEO has to participate the conference. It’s the rule.","TWN":"只有公司老闆可以參與會議，不能找代理人。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"따라서 이번 주말 일정을 비워 두셨으면 합니다만?","JPN":"したがって、今週末は予定を空けておいてください。","ENG":"So I want you to attend the conference this weekend.","TWN":"所以，希望這週末老闆可以盡量把時間空下來，好嗎？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"대체 누군가! 이런 허례허식을 만들어 둔 인간이!","JPN":"いったい誰が！　こんな無意味な慣例を作ったのだ！","ENG":"I say, we should get rid of all the empty formalities and vanity.","TWN":"到底是誰！哪個可惡的傢伙！搞這種繁文縟節幹嘛！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……본인이 가장 잘 알고 계셔야죠.","JPN":"……それは本人が一番知っているのでは？","ENG":"Of which you should know the best above anyone else.","TWN":"……這個你本人應該最清楚吧？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"잠깐, 그럼 사장이 주말 출근을 하는데 자네도 동행하는 거겠지?","JPN":"待てよ、社長が週末に出勤するんだ。もちろん君も同行するのだろう？","ENG":"So you’re accompanying me to the conference, right? It’s official business.","TWN":"等等！老闆週末要上班的話，那你也應該要陪同吧？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님께서 일하시는데 부하 직원이 편히 쉴 수는 없죠.","JPN":"社長が働いているのに、部下が休むわけにはいきません。","ENG":"I will be going to work as well.","TWN":"老闆在工作，員工當然不會閒著囉。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 컨퍼런스에는 혼자 가셔야 할 겁니다.","JPN":"ですが、コンファレンスにはお一人で行っていただきます。","ENG":"But not to the conference.","TWN":"不過我不能陪你去開會，你要自己去。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"왜, 왜지?","JPN":"な、なぜだ？","ENG":"Why not?!","TWN":"為…為什麼？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저도 따로 출장이 있거든요.","JPN":"私は別の出張がありますので。","ENG":"I have a business trip scheduled that weekend.","TWN":"因為我也要去出差。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};